import { uniCalendar } from "../../components/uni-calendar/uni-calendar.vue";
export default {
    components: {
        uniCalendar
    },
    data() {
        return {
            meetingroomCode: null,
            meetingroomName: null,
            dataList: [],
            date: null
        };
    },
    methods: {
        change(e) {
            this.date = e.fulldate;
            console.log(e);
        },
        goDetail(item) {
            uni.navigateTo({
                url:
                    "/pages/meeting/meeting?data=" +
                    encodeURIComponent(JSON.stringify(item))
            });
        },
        editItem(item) {
            uni.navigateTo({
                url:
                    "/pages/meeting/meeting?data=?flag=modify&data=" +
                    JSON.stringify(item)
            });
        },
        deleteItem(item) {
            this.modalName = null;
            var _this = this;
            uni.showModal({
                title: "操作提示",
                content: "确定删除选中项?",
                success(res) {
                    if (res.confirm) {
                        item.UIStatus = "Delete";
                        item.Canceled = "Yes";
                        _this.$mbservices.Request(
                            _this.$webapi.submitBorrowRequest,
                            "POST",
                            item,
                            function(succ) {
                                console.log(succ);
                                if (succ.statusCode === 200) {
                                    var cache = [];
                                    _this.dataList.forEach(_item => {
                                        if (_item != item) {
                                            cache.push(_item);
                                        }
                                    });
                                    _this.dataList = [];
                                    cache.forEach(_item => {
                                        _this.dataList.push(_item);
                                    });
                                }
                            },
                            function(err) {
                                console.log(err);
                            }
                        );
                    }
                }
            });
        },
        // ListTouch触摸开始
        ListTouchStart(indx, e) {
            if (
                this.dataList[indx].Approve === "Yes" &&
                (this.dataList[indx].ApproveStatus === "Pending" ||
                    this.dataList[indx].ApproveStatus === "Approved")
            ) {
                return false;
            }
            this.listTouchStart = e.touches[0].pageX;
        },

        // ListTouch计算方向
        ListTouchMove(indx, e) {
            if (
                this.dataList[indx].Approve === "Yes" &&
                (this.dataList[indx].ApproveStatus === "Pending" ||
                    this.dataList[indx].ApproveStatus === "Approved")
            ) {
                return false;
            }
            this.listTouchDirection =
                e.touches[0].pageX - this.listTouchStart > 0 ? "right" : "left";
        },

        // ListTouch计算滚动
        ListTouchEnd(indx, e) {
            if (
                this.dataList[indx].Approve === "Yes" &&
                (this.dataList[indx].ApproveStatus === "Pending" ||
                    this.dataList[indx].ApproveStatus === "Approved")
            ) {
                return false;
            }
            if (this.listTouchDirection == "left") {
                this.modalName = e.currentTarget.dataset.target;
            } else {
                this.modalName = null;
            }
            this.listTouchDirection = null;
        },
        booking() {
            uni.navigateTo({
                url:
                    "/pages/meeting/meeting?method=add&meetingroom" +
                    encodeURIComponent(JSON.stringify(this.meetingroomCode)) +
                    "&date=" +
                    encodeURIComponent(JSON.stringify(this.date))
            });
        },
        loadMore() {
            this.pageIndex = parseInt(this.pageIndex) + 1;
            let ajaxJSON = {
                pageIndex: this.pageIndex,
                rowsPerPage: "5",
                type: "Initialize",
                Parameter: {
                    Sorts: [
                        {
                            FieldName: "DocEntry",
                            type: "Descending"
                        }
                    ],
                    LoadChildren: "NoLoad",
                    Conditions: [
                        {
                            FieldName: "Canceled",
                            Operation: "EQUAL",
                            ConditionValue: "N",
                            Relationship: "AND"
                        }
                    ]
                }
            };
            if (params != undefined && params.length > 0) {
                params.forEach(item => {
                    ajaxJSON.Parameter.Conditions.push(item);
                });
            }
            let _this = this;
            this.$mbservices.Request(
                this.$webapi.getBorrowRequestList,
                "POST",
                ajaxJSON,
                ret => {
                    console.log(ret);
                    if (!ret.data.data) {
                        _this.dataList = [];
                        uni.showToast({
                            title: "查无数据"
                        });
                        return false;
                    }
                    let _cacheList = [];
                    ret.data.data.forEach(item => {
                        _this.dataList.push(item);
                    });
                },
                ret => {
                    uni.showToast({
                        title: ret.errMsg,
                        icon: "none",
                        success: function() {
                            setTimeout(function() {
                                uni.navigateBack();
                            }, 1000);
                        }
                    });
                }
            );
        }
    },
    onLoad(option) {
        try {
            this.meetingroomCode = JSON.parse(option.meetingroomCode);
            this.meetingroomName = JSON.parse(option.meetingroomName);
            //获取
        } catch (e) {
            //TODO handle the exception
            uni.showToast({
                title: "获取DocEntry失败",
                icon: "none"
            });
        }
    }
};
